      { type:"mc", q:"What is the federal transfer tax required when purchasing a suppressor or other NFA item?", options:["$50","$100","$200","$500"], correct:2, explanation:"The NFA imposes a $200 tax on the transfer of Title II weapons (suppressors, SBRs, SBSs, machine guns, AOWs — except AOWs which are $5 to transfer). This tax has not changed since 1934." },
      { type:"tf", q:"A suppressor reduces gunshot noise to near-silence, as commonly depicted in movies.", correct:false, explanation:"Suppressors reduce sound by 20-35 dB — typically bringing a gunshot from ~165 dB to ~130-140 dB. Still loud, but hearing-safe with proper protection. Not Hollywood silent." },
      { type:"fill", q:"The ATF form used to transfer an NFA item from a licensed dealer to an individual buyer is Form ___.", options:["1","3","4","5320"], correct:2, explanation:"Form 4 is the Application for Tax Paid Transfer. Form 1 is to make your own NFA item. Form 3 is dealer-to-dealer transfer. All require ATF approval before transfer." },
      { type:"mc", q:"Under the NFA, a Short-Barreled Rifle (SBR) is defined as having a rifle barrel shorter than:", options:["14 inches","16 inches","18 inches","20 inches"], correct:1, explanation:"SBR: overall length under 26\" or barrel under 16\". SBS (Short-Barreled Shotgun): barrel under 18\". Both require NFA registration and $200 tax." },
      { type:"tf", q:"The National Firearms Act was enacted in 1934 largely in response to gangland violence during Prohibition.", correct:true, explanation:"The NFA (1934) was Congress's response to the St. Valentine's Day Massacre (1929) and widespread gang violence. It regulated machine guns, suppressors, short-barrel firearms, and destructive devices." },
      { type:"mc", q:"Which of the following is NOT regulated under the NFA?", options:["Suppressors","Short-Barreled Rifles","A standard semi-automatic rifle with a 16\"+ barrel","Machine guns"], correct:2, explanation:"Standard semi-automatic rifles with barrels 16\"+ and overall length 26\"+ are Title I firearms — not NFA items. No special tax or registration required." },
      { type:"fill", q:"Machine guns manufactured after ___ cannot legally be transferred to civilians under the Hughes Amendment.", options:["January 1, 1986","May 19, 1986","November 1, 1994","December 31, 1989"], correct:1, explanation:"The Hughes Amendment (FOPA 1986) closed the civilian machine gun registry. Pre-May 19, 1986 registered machine guns can still be transferred — but they're rare and expensive ($15,000–$50,000+)." },
      { type:"tf", q:"A trust or LLC can legally own NFA items.", correct:true, explanation:"NFA trusts and legal entities can own NFA items. This allows multiple trustees to legally possess the items without requiring a law enforcement sign-off (Chief Law Enforcement Officer sign-off was previously required for individuals)." },
      { type:"mc", q:"Current typical ATF Form 4 individual transfer wait times for suppressors are approximately:", options:["1-2 weeks","1-2 months","6-12+ months","3-5 years"], correct:2, explanation:"Form 4 e-file times have improved, but individual transfers typically take 6-12+ months. Trust/entity transfers may differ. Advise customers to plan ahead." },
      { type:"tf", q:"Moving an NFA item across state lines requires prior written approval from the ATF.", correct:true, explanation:"You must file ATF Form 20 (or use the ATF eForms system) to get approval before transporting an NFA item across state lines. Failure to do so is a federal felony." },
      { type:"mc", q:"Suppressors primarily reduce sound by:", options:["Eliminating the sonic crack of the bullet","Slowing and cooling the expanding propellant gases as they exit the muzzle","Absorbing the mechanical sound of the action","Reducing the powder charge"], correct:1, explanation:"Suppressors provide a series of chambers (baffles) that allow the hot gases to expand and cool before exiting. This is the primary noise reduction mechanism." },
      { type:"fill", q:"In Colorado, suppressors are ___ to purchase and own with proper federal NFA paperwork.", correct:0, options:["Legal","Illegal","Restricted to law enforcement","Subject to an additional state tax"], explanation:"Colorado does not prohibit suppressor ownership. Federal NFA compliance (Form 4, $200 tax, ATF approval) is required. Approximately 42 states allow civilian suppressor ownership." }
